import{_ as a,o as t,c as s,a2 as n}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"Dojang and attesters","description":"","frontmatter":{},"headers":[],"relativePath":"internals/dojang.md","filePath":"internals/dojang.md"}'),o={name:"internals/dojang.md"};function r(i,e,d,c,h,p){return t(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="dojang-and-attesters" tabindex="-1">Dojang and attesters <a class="header-anchor" href="#dojang-and-attesters" aria-label="Permalink to &quot;Dojang and attesters&quot;">​</a></h1><p>Dojang is GIWA&#39;s verified-address system. Suho reads it to decide who is a verified human. It never mocks these reads.</p><h2 id="how-verification-is-read" tabindex="-1">How verification is read <a class="header-anchor" href="#how-verification-is-read" aria-label="Permalink to &quot;How verification is read&quot;">​</a></h2><p>A recipient is verified if <code>DojangScroll.isVerified(address, attesterId)</code> returns true for any accepted attester. Suho accepts two attester ids, in order: the testnet faucet issuer first, and the Upbit Korea issuer second.</p><p>The attester id is configuration, not a constant baked into the guard. It lives in <code>DojangConfig</code> and is passed to the guard at deploy time. No contract hardcodes an attester id anywhere else.</p><h2 id="up-id-names" tabindex="-1">up.id names <a class="header-anchor" href="#up-id-names" aria-label="Permalink to &quot;up.id names&quot;">​</a></h2><p>Names come from the UpnameRegistry, the &quot;Upbit Web3 Names&quot; contract. It is not ENS-style. There is no separate resolver and no namehash.</p><p>The token id is the keccak hash of the bare label. Forward resolution reads <code>ownerOf(tokenId)</code>. Reverse resolution reads the label for the token owned by an address. A name is only shown when its owner has an active name.</p><h2 id="in-app-verification" tabindex="-1">In-app verification <a class="header-anchor" href="#in-app-verification" aria-label="Permalink to &quot;In-app verification&quot;">​</a></h2><p>New accounts verify themselves. The app builds a Dojang faucet-issuance call and routes it through the account&#39;s own <code>execute()</code> with a passkey signature. The account performs its own verification. The guardian only relays.</p><p>Verification is a third-party attestation by nature, so the issuer being a fixed testnet attester is honest. The name claim is different. It must come from the account itself, because the registry assigns the name to <code>msg.sender</code>.</p><p>Contract addresses are on the <a href="/docs/developers/contracts.html">Contracts and addresses</a> page.</p>',12)])])}const f=a(o,[["render",r]]);export{u as __pageData,f as default};
